const pred = msg.pred || {};
const v = msg.payload || {};

function minsToHuman(mins) {
  const m = Number(mins);
  if (!Number.isFinite(m)) return "--";
  if (m < 60) return `${m} min`;
  const h = Math.round((m / 60) * 10) / 10;
  return `${h} h`;
}

function labelToText(label) {
  if (label === "URGENT") return "Urgence";
  if (label === "WARNING") return "À surveiller";
  if (label === "NORMAL") return "Normal";
  return label || "--";
}

function adviceToText(code) {
  switch (code) {
    case "ADVICE_MONITOR":
      return "Rien d’inquiétant. Continue à surveiller et refais une mesure plus tard.";
    case "ADVICE_REMEASURE":
      return "Refais une mesure au repos (doigt bien placé) dans quelques minutes.";
    case "ADVICE_URGENT":
      return "Valeurs préoccupantes. Si tu as des symptômes (douleur, essoufflement, malaise), demande de l’aide rapidement.";
    default:
      return "Conseil: garde-toi au calme et refais une mesure si tu te sens mal.";
  }
}

const tsVitals = v.ts || "(inconnu)";
const bpm = (v.bpm ?? "--");
const spo2 = (v.spo2 ?? "--");
const temp = (v.temp === null || v.temp === undefined) ? "--" : Number(v.temp).toFixed(1);

const need = Number(pred.need_remeasure) === 1;
const next = minsToHuman(pred.remeasure_in_min);
const followUp = need
  ? `Refaire une mesure: OUI (dans ${next})`
  : `Prochaine mesure conseillée: dans ${next}`;

const text =
  `Dernière analyse NexPulse\n` +
  `• Mesure: ${tsVitals}\n` +
  `• BPM: ${bpm} | SpO2: ${spo2}% | Temp: ${temp}°C\n` +
  `• État: ${labelToText(pred.label)}\n` +
  `• ${adviceToText(pred.advice_code)}\n` +
  `• ${followUp}`;

// IMPORTANT: Passer les vitals dans une propriété séparée
msg.vitals = {
  ts: v.ts,
  bpm: v.bpm,
  spo2: v.spo2,
  temp: v.temp
};
msg.pred = pred;
msg.chatId = msg.chatId;

// Le message à afficher
msg.payload = {
  chatId: msg.chatId,
  type: "message",
  content: text
};

return msg;

