flow.set('reminder_mode', 'SILENCE_NORMAL');
const chatId = msg.payload.chatId;
msg.payload = { chatId, type: 'message', content: '✅ Rappels: Silence si NORMAL (rappels seulement si besoin ou état non normal)' };
