flow.set('reminder_mode', 'SILENT');
const chatId = msg.payload.chatId;
msg.payload = { chatId, type: 'message', content: '✅ Rappels désactivés (silence total)' };
return msg;

const p = msg.payload || {};

// --- settings ---
const mode = flow.get('reminder_mode') || 'SILENCE_NORMAL';

// label: NORMAL/WARNING/URGENT
const label = (p.label || '').toString();
const need = Number(p.need_remeasure) === 1;
const mins = Number(p.remeasure_in_min);

if (mode === 'SILENT') return null;
if (!Number.isFinite(mins) || mins <= 0) return null;

// SILENCE_NORMAL: only remind if not NORMAL OR if need_remeasure=1
if (mode === 'SILENCE_NORMAL') {
  if (!need && label === 'NORMAL') return null;
}

// chatId: you used a fixed chat id. If you want per-user later, we can store chatId.
const chatId = 7990324298;

// Cancel previous reminders by using a constant topic
const baseTopic = 'NEXPULSE_REMEASURE';

function buildReminder(delayMs, whenLabel) {
  return {
    topic: baseTopic,
    delay: delayMs,
    payload: {
      chatId,
      type: 'message',
      content: `⏰ Rappel NexPulse (${whenLabel}) : pense à refaire une mesure.`
    }
  };
}

// target time: mins from now
const T = mins * 60 * 1000;
const tMinus = Math.max(0, T - 5 * 60 * 1000);
const tPlus  = T + 5 * 60 * 1000;

// We send 3 separate messages through delay nodes
return [
  buildReminder(tMinus, 'dans 5 min'),
  buildReminder(T, 'maintenant'),
  buildReminder(tPlus, 'il y a 5 min')
];

// TEMP TEST: force 1 minute
msg.payload.remeasure_in_min = 1;
msg.payload.need_remeasure = 1;
return msg;

