};

return msg;

flow.set('audio_mode', 'ALWAYS');
const chatId = msg.payload.chatId;
msg.payload = { chatId, type: 'message', content: '✅ Audio automatique: Toujours' };
return msg;

flow.set('audio_mode', 'URGENT_ONLY');
const chatId = msg.payload.chatId;
msg.payload = { chatId, type: 'message', content: '✅ Audio automatique: seulement si URGENT' };
return msg;

flow.set('audio_mode', 'NEVER');
const chatId = msg.payload.chatId;
msg.payload = { chatId, type: 'message', content: '✅ Audio automatique: Jamais (tu peux toujours utiliser /audio)' };
return msg;

const chatId = msg.chatId || msg.payload?.chatId || 7990324298;
const pred = msg.pred || {};
const label = (pred.label || "").toString();

const mode = flow.get("audio_mode") || "URGENT_ONLY";

let should = false;
if (mode === "ALWAYS") should = true;
if (mode === "NEVER") should = false;
if (mode === "URGENT_ONLY") should = (label === "URGENT");

if (!should) return null;

// message "factice" qui déclenche le flow audio
return {
  payload: {
    chatId,
    content: "/audio"
  }
};

// Récupérer les données depuis msg.vitals (pas depuis msg.payload)
const pred = msg.pred || {};
const v = msg.vitals || {};  // ← Changement important ici

const name = flow.get('user_name') || '';
const age = Number(flow.get('user_age'));
const sporty = flow.get('user_sporty');

const label = (pred.label || '').toString();
const extra = [];
const isElder = Number.isFinite(age) && age >= 65;
const isSporty = sporty === true;

if (label === 'URGENT') {
  if (isElder) extra.push('Vu ton âge, évite tout effort et reste au calme.');
  if (isSporty) extra.push('Même si tu es sportif, évite l\'activité physique et reste au repos pour vérifier.');
}

// Extraction des valeurs - maintenant depuis v
let bpm = null;
let spo2 = null;
let temp = null;

if (v.bpm !== undefined && v.bpm !== null) bpm = Number(v.bpm);
if (v.spo2 !== undefined && v.spo2 !== null) spo2 = Number(v.spo2);
if (v.temp !== undefined && v.temp !== null) temp = Number(v.temp);

// Conseils personnalisés basés sur les valeurs
if (label !== 'NORMAL' && Number.isFinite(bpm) && bpm > 120) {
  extra.push('Rythme cardiaque élevé: assieds-toi et respire lentement.');
}
if (Number.isFinite(spo2) && spo2 > 0 && spo2 < 92) {
  extra.push('Saturation basse: évite l\'effort et demande de l\'aide si symptômes.');
}
if (Number.isFinite(temp) && temp >= 38.5) {
  extra.push('Température élevée: hydrate-toi et surveille l\'évolution.');
}

// Récupérer le message de base
let base = (msg.payload && msg.payload.content) ? msg.payload.content : '';

// Ajouter le nom de l'utilisateur si disponible
if (name) {
  base = 'Bonjour ' + name + '.\n\n' + base;
}

// Ajouter les conseils personnalisés
if (extra.length) {
  base += '\n\n💡 Conseils personnalisés:\n' + extra.map(s => '• ' + s).join('\n');
}

// Stocker les données pour l'explication
const vitalsToStore = {
  ts: v.ts || new Date().toISOString(),
  bpm: bpm,
  spo2: spo2,
  temp: temp
};

// Stocker dans le flow
flow.set('last_pred', pred);
flow.set('last_vitals', vitalsToStore);

// DEBUG
node.warn("=== STORED IN FLOW ===");
node.warn("last_pred: " + JSON.stringify(pred));
node.warn("last_vitals: " + JSON.stringify(vitalsToStore));

// Construire le message avec le bouton Explication
msg.payload = {
  chatId: msg.chatId,
  type: 'message',
  content: base,
  options: {
    reply_markup: {
      keyboard: [
        [{ text: 'ℹ️ Explication' }],
        [{ text: '⬅️ Retour menu' }]
      ],
      resize_keyboard: true,
      one_time_keyboard: false
    }
  }
};

return msg;

const chatId = msg.payload.chatId;
const pred = flow.get('last_pred') || {};
let v = flow.get('last_vitals') || {};

// DEBUG - Affiche ce qui est stocké
node.warn("=== DEBUG explain ===");
node.warn("pred: " + JSON.stringify(pred));
node.warn("v BEFORE fix: " + JSON.stringify(v));

// Si v est vide ou mal structuré, essaie de lire depuis le fichier
if (!v.bpm && !v.spo2 && !v.temp) {
    // Essayer de lire depuis le flow context ou récupérer depuis le dernier message
    node.warn("Vitals manquants, tentative de récupération...");

    // Option: lire depuis le fichier last_vitals.json directement
    const fs = require('fs');
    const path = 'C:\\Users\\JBL\\Desktop\\NexPulse\\last_vitals.json';
    try {
        const fileContent = fs.readFileSync(path, 'utf8');
        const fileVitals = JSON.parse(fileContent);
        if (fileVitals && (fileVitals.bpm !== undefined || fileVitals.spo2 !== undefined)) {
            v = fileVitals;
            node.warn("Récupéré depuis fichier: " + JSON.stringify(v));
        }
    } catch(e) {
        node.warn("Erreur lecture fichier vitals: " + e.message);
    }
}

// Extraction des valeurs avec fallbacks
let bpm = null;
let spo2 = null;
let temp = null;

// Essayer différents chemins
if (v.bpm !== undefined && v.bpm !== null) bpm = Number(v.bpm);
else if (v.payload && v.payload.bpm !== undefined) bpm = Number(v.payload.bpm);

if (v.spo2 !== undefined && v.spo2 !== null) spo2 = Number(v.spo2);
else if (v.payload && v.payload.spo2 !== undefined) spo2 = Number(v.payload.spo2);

if (v.temp !== undefined && v.temp !== null) temp = Number(v.temp);
else if (v.payload && v.payload.temp !== undefined) temp = Number(v.payload.temp);

node.warn("Valeurs extraites - bpm:" + bpm + " spo2:" + spo2 + " temp:" + temp);

const label = (pred.label || '').toString();

const reasons = [];
const normalSignals = [];

// Analyse SpO2
if (Number.isFinite(spo2) && spo2 > 0) {
    if (spo2 < 92) reasons.push('SpO2 basse (' + spo2 + '%)');
    else if (spo2 < 95) reasons.push('SpO2 un peu basse (' + spo2 + '%)');
    else normalSignals.push('SpO2 normale (' + spo2 + '%)');
} else if (spo2 === 0) {
    normalSignals.push('SpO2: ' + spo2 + '% (vérifie le capteur)');
} else {
    normalSignals.push('SpO2: donnée non disponible');
}

// Analyse BPM
if (Number.isFinite(bpm) && bpm > 0) {
    if (bpm > 130) reasons.push('BPM très élevé (' + bpm + ')');
    else if (bpm > 100) reasons.push('BPM élevé (' + bpm + ')');
    else if (bpm < 60) reasons.push('BPM bas (' + bpm + ')');
    else normalSignals.push('BPM normal (' + bpm + ')');
} else if (bpm === 0) {
    normalSignals.push('BPM: ' + bpm + ' (capteur non détecté)');
} else {
    normalSignals.push('BPM: donnée non disponible');
}

// Analyse Température
if (Number.isFinite(temp) && temp > 0) {
    if (temp >= 39) reasons.push('Température très élevée (' + temp.toFixed(1) + '°C)');
    else if (temp >= 38.5) reasons.push('Température élevée (' + temp.toFixed(1) + '°C)');
    else if (temp <= 35.5) reasons.push('Température basse (' + temp.toFixed(1) + '°C)');
    else normalSignals.push('Température normale (' + temp.toFixed(1) + '°C)');
} else if (temp === 0) {
    normalSignals.push('Température: 0°C (vérifie le capteur)');
} else {
    normalSignals.push('Température: donnée non disponible');
}

let headline = label || '--';
if (label === 'WARNING') headline = 'À surveiller';
if (label === 'URGENT') headline = 'URGENCE';
if (label === 'NORMAL') headline = 'Normale';

let text = '📊 Explication: pourquoi l\'état est "' + headline + '"\n\n';

if (reasons.length > 0) {
    text += '⚠️ Signaux détectés:\n' + reasons.map(r => '• ' + r).join('\n');
} else if (label === 'NORMAL') {
    text += '✅ Signes vitaux mesurés:\n' + normalSignals.map(s => '• ' + s).join('\n');
} else {
    text += '📈 Valeurs mesurées:\n' + normalSignals.map(s => '• ' + s).join('\n');
}

// Ajouter les valeurs brutes pour transparence
text += '\n\n📊 Valeurs brutes: BPM=' + (Number.isFinite(bpm) ? bpm : '?') + 
        ' | SpO2=' + (Number.isFinite(spo2) ? spo2 : '?') + '%' +
        ' | T=' + (Number.isFinite(temp) ? temp.toFixed(1) : '?') + '°C';

text += '\n\n⚠️ Rappel: ce bot ne remplace pas un avis médical.';

msg.payload = {
    chatId,
    type: 'message',
    content: text,
    options: {
        reply_markup: {
            keyboard: [
                [{ text: 'Dernière prédiction' }],
                [{ text: '⬅️ Retour menu' }]
            ],
            resize_keyboard: true,
            one_time_keyboard: false
        }
    }
};
return msg;

const chatId = msg.payload.chatId;
const currentState = flow.get('onboard_state') || '';

if (currentState !== 'ASK_SPORTY') return null;

flow.set('user_sporty', false);
flow.set('onboard_state', 'COMPLETED');  // ← Important: marquer comme complété

const name = flow.get('user_name') || '';

msg.payload = { 
    chatId, 
    type: 'message', 
    content: '✅ Profil enregistré. Bonjour ' + name + ' !\n\nTape "Menu" pour commencer à utiliser NexPulse.',
    options: {
        reply_markup: {
            keyboard: [
                [{ text: "Menu" }]
            ],
            resize_keyboard: true
        }
    }
};

return msg;

const chatId = msg.payload.chatId;
const currentState = flow.get('onboard_state') || '';

if (currentState !== 'ASK_SPORTY') return null;

flow.set('user_sporty', true);
flow.set('onboard_state', 'COMPLETED');  // ← Important: marquer comme complété

const name = flow.get('user_name') || '';

msg.payload = { 
    chatId, 
    type: 'message', 
    content: '✅ Profil enregistré. Bonjour ' + name + ' !\n\nTape "Menu" pour commencer à utiliser NexPulse.',
    options: {
        reply_markup: {
            keyboard: [
                [{ text: "Menu" }]
            ],
            resize_keyboard: true
        }
    }
};

return msg;

const chatId =
  msg.payload?.chatId ||
  msg.payload?.message?.chat?.id ||
  msg.chatId ||
  7990324298;

// Extraction robuste du texte
const p = msg.payload || {};
const text =
  (typeof p.content === "string" && p.content) ||
  (typeof p.text === "string" && p.text) ||
  (typeof p.message?.text === "string" && p.message.text) ||
  (typeof p.message?.caption === "string" && p.message.caption) ||
  "";

const clean = text.trim();

// =====================================================
// IMPORTANT : ignorer les boutons "sportif"
// Ils sont déjà traités par :
// - np_onboard_set_sporty_yes
// - np_onboard_set_sporty_no
// =====================================================
if (
  clean === "✅ Oui, sportif" ||
  clean === "❌ Non, pas sportif"
) {
  return null;
}

const state = flow.get("onboard_state") || "";

// Si onboarding terminé, ignorer tout
if (state === "COMPLETED") {
  return null;
}

// Si aucun état actif, ignorer
if (!state) {
  return null;
}

// =====================================================
// ASK_SPORTY : forcer l'utilisation des boutons
// =====================================================
if (state === "ASK_SPORTY") {
  msg.payload = {
    chatId,
    type: "message",
    content: "Veuillez utiliser les boutons pour répondre :",
    options: {
      reply_markup: {
        keyboard: [
          [{ text: "✅ Oui, sportif" }],
          [{ text: "❌ Non, pas sportif" }]
        ],
        resize_keyboard: true,
        one_time_keyboard: true
      }
    }
  };
  return msg;
}

// =====================================================
// ASK_NAME
// =====================================================
if (state === "ASK_NAME") {
  if (!clean) {
    msg.payload = {
      chatId,
      type: "message",
      content: "Donne juste ton prénom."
    };
    return msg;
  }

  const name = clean.substring(0, 30);

  flow.set("user_name", name);
  flow.set("onboard_state", "ASK_AGE");

  msg.payload = {
    chatId,
    type: "message",
    content: `Enchanté ${name}. Quel âge as-tu ? (ex: 28)`
  };
  return msg;
}

// =====================================================
// ASK_AGE
// =====================================================
if (state === "ASK_AGE") {
  if (!clean || clean.length === 0) {
    msg.payload = {
      chatId,
      type: "message",
      content: "Quel âge as-tu ? (ex: 28)"
    };
    return msg;
  }

  const age = Number(clean.replace(",", "."));

  if (!Number.isFinite(age) || age <= 0 || age > 120) {
    msg.payload = {
      chatId,
      type: "message",
      content: "Âge invalide. Exemple: 28"
    };
    return msg;
  }

  flow.set("user_age", Math.round(age));
  flow.set("onboard_state", "ASK_SPORTY");

  msg.payload = {
    chatId,
    type: "message",
    content: "Es-tu sportif (activité régulière) ? Choisis un bouton.",
    options: {
      reply_markup: {
        keyboard: [
          [{ text: "✅ Oui, sportif" }],
          [{ text: "❌ Non, pas sportif" }]
        ],
        resize_keyboard: true,
        one_time_keyboard: true
      }
    }
  };
  return msg;
}

// =====================================================
// Aucun état reconnu
// =====================================================
return null;

const chatId = msg.payload.chatId;

flow.set('onboard_state', 'ASK_NAME');
msg.payload = {
    chatId,
    type: 'message',
    content: 'Bienvenue sur NexPulse. Comment tu t\'appelles ?'
};
return msg;

const name = flow.get('user_name') || 'Non renseigné';
const age = flow.get('user_age');
const sporty = flow.get('user_sporty');

let sportyText = '';
if (sporty === true) sportyText = '✅ Oui, sportif';
else if (sporty === false) sportyText = '❌ Non sportif';
else sportyText = 'Non renseigné';

const ageText = age ? `${age} ans` : 'Non renseigné';

msg.payload = `Nom : ${name}\nÂge : ${ageText}\nSportif : ${sportyText}`;
return msg;

const chatId =
  msg.payload?.chatId ||
  msg.payload?.message?.chat?.id ||
  msg.chatId ||
  7990324298;

// Extraction robuste du texte
const p = msg.payload || {};
const text = (
